1	/**
2	 * Blind mode projection service.
3	 *
4	 * Column-level access control for review data.
5	 * Column selection happens in the service (before the SQL query),
6	 * not in a post-fetch serializer. This means identity data is NEVER
7	 * fetched in blind mode — a projection bug cannot cause a data leak.
8	 *
9	 * Modes:
10	 *   blind      — only score-related fields; no applicant identity whatsoever
11	 *   semi_blind — academic context (program, cycle) but no personal identifiers
12	 *   full       — all fields (SYSTEM_ADMIN and PROGRAM_ADMIN only)
13	 */
14	
15	// Fields visible in each mode
16	const BLIND_COLUMNS = [
17	  'ra.id',
18	  'ra.application_id',
19	  'ra.status',
20	  'ra.assigned_at',
21	  'ra.submitted_at',
22	  'ra.blind_mode',
23	];
24	
25	const SEMI_BLIND_COLUMNS = [
26	  ...BLIND_COLUMNS,
27	  'a.cycle_id',
28	  'a.status AS application_status',
29	  'a.research_fit_score',
30	  'a.submitted_at AS application_submitted_at',
31	];
32	
33	const FULL_COLUMNS = [
34	  ...SEMI_BLIND_COLUMNS,
35	  'a.account_id AS applicant_account_id',
36	  'a.applicant_name_encrypted',
37	  'a.contact_email_encrypted',
38	];
39	
40	/**
41	 * Returns the column list appropriate for the given blind mode.
42	 * @param {'blind'|'semi_blind'|'full'} mode
43	 * @returns {string[]}
44	 */
45	export function getColumnsForMode(mode) {
46	  switch (mode) {
47	    case 'full':
48	      return FULL_COLUMNS;
49	    case 'semi_blind':
50	      return SEMI_BLIND_COLUMNS;
51	    case 'blind':
52	    default:
53	      return BLIND_COLUMNS;
54	  }
55	}
56	
57	/**
58	 * Determines the effective blind mode for a viewer.
59	 * Reviewers always get their assignment's configured blind mode.
60	 * Admins may request 'full' mode.
61	 *
62	 * @param {object} assignment  review_assignments row
63	 * @param {object} viewer      { id, roles }
64	 * @returns {'blind'|'semi_blind'|'full'}
65	 */
66	export function resolveMode(assignment, viewer) {
67	  const isAdmin =
68	    viewer.roles?.includes('SYSTEM_ADMIN') || viewer.roles?.includes('PROGRAM_ADMIN');
69	
70	  if (isAdmin) return 'full';
71	  return assignment.blind_mode || 'blind';
72	}
73	
74	/**
75	 * Strips any identity fields from an already-fetched object as a safety net.
76	 * This is a belt-and-suspenders check — the primary protection is column-level selection.
77	 *
78	 * @param {object} row
79	 * @param {'blind'|'semi_blind'|'full'} mode
80	 * @returns {object}
81	 */
82	export function projectRow(row, mode) {
83	  if (mode === 'full') return row;
84	
85	  const IDENTITY_FIELDS = ['applicant_account_id', 'applicant_name_encrypted', 'contact_email_encrypted'];
86	  const result = { ...row };
87	
88	  if (mode === 'blind' || mode === 'semi_blind') {
89	    for (const field of IDENTITY_FIELDS) {
90	      delete result[field];
91	    }
92	  }
93	
94	  if (mode === 'blind') {
95	    delete result.cycle_id;
96	    delete result.application_status;
97	    delete result.research_fit_score;
98	    delete result.application_submitted_at;
99	  }
100	
101	  return result;
102	}
