1	import { createHash } from 'crypto';
2	import { promises as fsPromises } from 'fs';
3	import { requestFingerprint } from '../crypto/tokens.js';
4	import { idempotencyRepository } from './idempotency.repository.js';
5	import { ConflictError } from '../errors/AppError.js';
6	import logger from '../logging/logger.js';
7	
8	// HTTP methods that require idempotency protection
9	const IDEMPOTENT_METHODS = new Set(['POST', 'PUT', 'PATCH', 'DELETE']);
10	
11	/**
12	 * Idempotency-key middleware.
13	 *
14	 * For authenticated write requests (POST/PUT/PATCH/DELETE):
15	 *   - Missing Idempotency-Key header → 400 MISSING_IDEMPOTENCY_KEY
16	 *   - Key present, no prior record → reserve slot, execute handler, complete slot
17	 *   - Key present, matching fingerprint, completed → return cached response (deduplication)
18	 *   - Key present, matching fingerprint, pending → 409 (concurrent in-flight request)
19	 *   - Key present, different fingerprint → 409 Conflict
20	 *
21	 * Unauthenticated write requests (e.g. POST /v1/auth/login) are exempt.
22	 *
23	 * Atomicity guarantee: the slot is reserved via INSERT … ON CONFLICT DO NOTHING
24	 * before the handler runs, so two concurrent requests with the same key race at the
25	 * DB level. Only one wins the INSERT; the other finds the existing record and either
26	 * replays the cached response or returns 409 (still pending).
27	 */
28	export function idempotencyMiddleware() {
29	  return async function idempotency(ctx, next) {
30	    const idempotencyKey = ctx.get('Idempotency-Key');
31	
32	    // Skip non-write methods entirely
33	    if (!IDEMPOTENT_METHODS.has(ctx.method)) {
34	      await next();
35	      return;
36	    }
37	
38	    // Unauthenticated write requests (e.g. POST /v1/auth/login) bypass idempotency
39	    const accountId = ctx.state.user?.id;
40	    if (!accountId) {
41	      await next();
42	      return;
43	    }
44	
45	    // Authenticated write requests MUST supply an Idempotency-Key
46	    if (!idempotencyKey) {
47	      ctx.status = 400;
48	      ctx.body = {
49	        error: {
50	          code: 'MISSING_IDEMPOTENCY_KEY',
51	          message: 'Idempotency-Key header is required for authenticated write operations',
52	        },
53	        meta: { requestId: ctx.state.requestId },
54	      };
55	      return;
56	    }
57	
58	    // For multipart uploads, include file identity (size + SHA-256) in the fingerprint
59	    // so that re-uploading a different file with the same key is correctly detected as a conflict.
60	    let fileIdentity = {};
61	    if (ctx.request.files && Object.keys(ctx.request.files).length > 0) {
62	      for (const [field, f] of Object.entries(ctx.request.files)) {
63	        const singleFile = Array.isArray(f) ? f[0] : f;
64	        if (singleFile?.filepath) {
65	          const buf = await fsPromises.readFile(singleFile.filepath);
66	          fileIdentity[field] = {
67	            size: singleFile.size,
68	            sha256: createHash('sha256').update(buf).digest('hex'),
69	          };
70	        }
71	      }
72	    }
73	    const fingerprintBody = Object.keys(fileIdentity).length
74	      ? { ...(ctx.request.body || {}), __files: fileIdentity }
75	      : (ctx.request.body || {});
76	    const fingerprint = requestFingerprint(ctx.method, ctx.path, fingerprintBody);
77	
78	    // Attempt to atomically reserve the slot before running the handler.
79	    // If reserve returns false, a record already exists for this (account, key).
80	    const reserved = await idempotencyRepository.reserve(accountId, idempotencyKey, fingerprint);
81	
82	    if (!reserved) {
83	      // Slot already existed — look up the record to decide what to return
84	      const existing = await idempotencyRepository.findByAccountAndKey(accountId, idempotencyKey);
85	
86	      if (!existing) {
87	        // Record existed when we tried to insert but has since expired — treat as new
88	        // Re-attempt the reserve; if it fails again another request is truly concurrent
89	        const retried = await idempotencyRepository.reserve(accountId, idempotencyKey, fingerprint);
90	        if (!retried) {
91	          ctx.status = 409;
92	          ctx.body = {
93	            error: {
94	              code: 'IDEMPOTENCY_KEY_IN_FLIGHT',
95	              message: 'A request with this Idempotency-Key is already being processed',
96	            },
97	            meta: { requestId: ctx.state.requestId },
98	          };
99	          return;
100	        }
101	        // Successfully reserved on retry — fall through to handler execution below
102	      } else {
103	        if (existing.request_fingerprint !== fingerprint) {
104	          throw new ConflictError(
105	            'Idempotency key already used with a different request body',
106	          );
107	        }
108	
109	        if (existing.response_status === 0) {
110	          // Still pending — concurrent in-flight request
111	          ctx.status = 409;
112	          ctx.body = {
113	            error: {
114	              code: 'IDEMPOTENCY_KEY_IN_FLIGHT',
115	              message: 'A request with this Idempotency-Key is already being processed',
116	            },
117	            meta: { requestId: ctx.state.requestId },
118	          };
119	          return;
120	        }
121	
122	        // Completed — replay cached response
123	        ctx.status = existing.response_status;
124	        const cached = typeof existing.response_body === 'string'
125	          ? JSON.parse(existing.response_body)
126	          : existing.response_body;
127	        // 204 responses have no body — only set if the cached payload is non-empty
128	        if (cached && Object.keys(cached).length > 0) {
129	          ctx.body = cached;
130	        }
131	        return;
132	      }
133	    }
134	
135	    // Slot is now reserved — execute the handler
136	    try {
137	      await next();
138	    } catch (err) {
139	      // Handler failed — release the pending slot so the client can retry
140	      await idempotencyRepository.deletePending(accountId, idempotencyKey).catch((e) => {
141	        // Log but do not suppress the original error
142	        logger.error({ err: e, accountId, idempotencyKey }, 'idempotency: failed to release pending slot after handler error');
143	      });
144	      throw err;
145	    }
146	
147	    // Handler succeeded — complete the slot with the real response.
148	    // Retried up to 3 times (50ms, 100ms backoff) before falling back to deletePending()
149	    // so the client is not stuck with 409 IN_FLIGHT responses for up to 24 hours.
150	    if (ctx.status >= 200 && ctx.status < 300) {
151	      let completeErr;
152	      for (let attempt = 0; attempt < 3; attempt++) {
153	        try {
154	          await idempotencyRepository.complete(accountId, idempotencyKey, ctx.status, ctx.body ?? {});
155	          completeErr = null;
156	          break;
157	        } catch (e) {
158	          completeErr = e;
159	          if (attempt < 2) await new Promise((r) => setTimeout(r, 50 * (attempt + 1)));
160	        }
161	      }
162	      if (completeErr) {
163	        // All retries exhausted — release the pending slot. The tradeoff is that a client
164	        // retry may re-execute the handler, but this is preferable to an indefinite 409 lock.
165	        logger.error({ err: completeErr, accountId, idempotencyKey, status: ctx.status },
166	          'idempotency: failed to complete slot after retries — releasing pending slot to unblock client');
167	        await idempotencyRepository.deletePending(accountId, idempotencyKey).catch((e) => {
168	          logger.error({ err: e, accountId, idempotencyKey },
169	            'idempotency: failed to release pending slot — key stuck pending until expiry');
170	        });
171	      }
172	    } else {
173	      // Non-2xx (e.g. validation error that slipped through) — release the slot
174	      await idempotencyRepository.deletePending(accountId, idempotencyKey).catch((e) => {
175	        logger.error({ err: e, accountId, idempotencyKey }, 'idempotency: failed to release pending slot after non-2xx response');
176	      });
177	    }
178	  };
179	}
