1	import Router from '@koa/router';
2	import { requirePermission } from '../../rbac/rbac.middleware.js';
3	import { validate } from '../../../common/middleware/validate.middleware.js';
4	import {
5	  publishVersionSchema,
6	  paginationSchema,
7	  versionParamsSchema,
8	} from './versioned.validator.js';
9	import { z } from 'zod';
10	
11	/**
12	 * Creates a standard versioned entity router.
13	 * All 8 university-data entities use this factory.
14	 *
15	 * @param {string} prefix       Route prefix e.g. '/universities'
16	 * @param {object} service      Versioned service instance
17	 * @param {object} createSchema Zod schema for create body
18	 * @param {object} fkFields     Map of camelCase body key → snake_case stable-table column
19	 *                              e.g. { universityId: 'university_id' } for schools
20	 */
21	export function makeVersionedRouter(prefix, service, createSchema, fkFields = {}) {
22	  const router = new Router({ prefix });
23	
24	  // POST /v1/{entity} — create entity + initial draft
25	  router.post(
26	    '/',
27	    requirePermission('university-data', 'write'),
28	    validate({ body: createSchema }),
29	    async (ctx) => {
30	      const { name } = ctx.request.body;
31	      const stableData = { name_normalized: name.toLowerCase().replace(/\s+/g, ' ').trim() };
32	      // Map entity-specific FK fields (camelCase from body → snake_case stable table column)
33	      for (const [camel, snake] of Object.entries(fkFields)) {
34	        if (ctx.request.body[camel] != null) stableData[snake] = ctx.request.body[camel];
35	      }
36	      const result = await service.create(stableData, ctx.request.body, ctx.state.user.id, ctx.state.requestId);
37	      ctx.status = 201;
38	      ctx.body = { data: result, meta: { requestId: ctx.state.requestId } };
39	    },
40	  );
41	
42	  // GET /v1/{entity} — list current active versions
43	  router.get(
44	    '/',
45	    requirePermission('university-data', 'read'),
46	    validate({ query: paginationSchema }),
47	    async (ctx) => {
48	      const result = await service.listCurrent({}, ctx.query);
49	      ctx.body = {
50	        data: result.rows,
51	        meta: { requestId: ctx.state.requestId, total: result.total, ...ctx.query },
52	      };
53	    },
54	  );
55	
56	  const stableIdParamsSchema = versionParamsSchema.pick({ stableId: true });
57	
58	  // GET /v1/{entity}/:stableId — get current active version
59	  router.get(
60	    '/:stableId',
61	    requirePermission('university-data', 'read'),
62	    validate({ params: stableIdParamsSchema }),
63	    async (ctx) => {
64	      const version = await service.findCurrent(ctx.params.stableId);
65	      ctx.body = { data: version, meta: { requestId: ctx.state.requestId } };
66	    },
67	  );
68	
69	  // GET /v1/{entity}/:stableId/current — alias
70	  router.get(
71	    '/:stableId/current',
72	    requirePermission('university-data', 'read'),
73	    validate({ params: stableIdParamsSchema }),
74	    async (ctx) => {
75	      const version = await service.findCurrent(ctx.params.stableId);
76	      ctx.body = { data: version, meta: { requestId: ctx.state.requestId } };
77	    },
78	  );
79	
80	  // GET /v1/{entity}/:stableId/versions — list version history
81	  router.get(
82	    '/:stableId/versions',
83	    requirePermission('university-data', 'read'),
84	    validate({ params: stableIdParamsSchema }),
85	    async (ctx) => {
86	      const history = await service.findHistory(ctx.params.stableId);
87	      ctx.body = {
88	        data: history,
89	        meta: { requestId: ctx.state.requestId, total: history.length },
90	      };
91	    },
92	  );
93	
94	  // GET /v1/{entity}/:stableId/versions/:versionId — specific version
95	  router.get(
96	    '/:stableId/versions/:versionId',
97	    requirePermission('university-data', 'read'),
98	    validate({ params: versionParamsSchema }),
99	    async (ctx) => {
100	      const version = await service.findVersionById(ctx.params.stableId, ctx.params.versionId);
101	      ctx.body = { data: version, meta: { requestId: ctx.state.requestId } };
102	    },
103	  );
104	
105	  // POST /v1/{entity}/:stableId/versions — create new draft
106	  router.post(
107	    '/:stableId/versions',
108	    requirePermission('university-data', 'write'),
109	    validate({ params: stableIdParamsSchema, body: createSchema }),
110	    async (ctx) => {
111	      const version = await service.createNewDraft(
112	        ctx.params.stableId,
113	        ctx.request.body,
114	        ctx.state.user.id,
115	        ctx.state.requestId,
116	      );
117	      ctx.status = 201;
118	      ctx.body = { data: version, meta: { requestId: ctx.state.requestId } };
119	    },
120	  );
121	
122	  // PATCH /v1/{entity}/:stableId/versions/:versionId — update draft
123	  router.patch(
124	    '/:stableId/versions/:versionId',
125	    requirePermission('university-data', 'write'),
126	    validate({ params: versionParamsSchema }),
127	    async (ctx) => {
128	      const version = await service.updateDraft(
129	        ctx.params.stableId,
130	        ctx.params.versionId,
131	        ctx.request.body,
132	        ctx.state.user.id,
133	        ctx.state.requestId,
134	      );
135	      ctx.body = { data: version, meta: { requestId: ctx.state.requestId } };
136	    },
137	  );
138	
139	  // POST /v1/{entity}/:stableId/versions/:versionId/publish — publish version
140	  router.post(
141	    '/:stableId/versions/:versionId/publish',
142	    requirePermission('university-data', 'publish'),
143	    validate({ params: versionParamsSchema, body: publishVersionSchema }),
144	    async (ctx) => {
145	      const version = await service.publish(
146	        ctx.params.stableId,
147	        ctx.params.versionId,
148	        ctx.state.user.id,
149	        ctx.state.requestId,
150	        ctx.request.body.effectiveFrom, // override stored effective_from if supplied
151	      );
152	      ctx.body = { data: version, meta: { requestId: ctx.state.requestId } };
153	    },
154	  );
155	
156	  // POST /v1/{entity}/:stableId/versions/:versionId/activate
157	  // Manually promotes the named scheduled version to active.
158	  // Rejects with 422 if the version's effective_from is still in the future.
159	  router.post(
160	    '/:stableId/versions/:versionId/activate',
161	    requirePermission('university-data', 'publish'),
162	    validate({ params: versionParamsSchema }),
163	    async (ctx) => {
164	      let version;
165	      try {
166	        version = await service.promoteScheduled(
167	          ctx.params.stableId,
168	          ctx.state.user.id,
169	          ctx.state.requestId,
170	          ctx.params.versionId,
171	        );
172	      } catch (err) {
173	        if (err.code === 'NOT_DUE') {
174	          ctx.status = 422;
175	          ctx.body = {
176	            error: { code: 'VERSION_NOT_DUE', message: err.message },
177	            meta: { requestId: ctx.state.requestId },
178	          };
179	          return;
180	        }
181	        throw err;
182	      }
183	      if (!version) {
184	        ctx.status = 404;
185	        ctx.body = {
186	          error: { code: 'NOT_FOUND', message: 'Version not found or not in scheduled state' },
187	          meta: { requestId: ctx.state.requestId },
188	        };
189	      } else {
190	        ctx.body = { data: version, meta: { requestId: ctx.state.requestId } };
191	      }
192	    },
193	  );
194	
195	  // POST /v1/{entity}/:stableId/archive — archive entity
196	  router.post(
197	    '/:stableId/archive',
198	    requirePermission('university-data', 'archive'),
199	    validate({ params: stableIdParamsSchema }),
200	    async (ctx) => {
201	      await service.archive(ctx.params.stableId, ctx.state.user.id, ctx.state.requestId);
202	      ctx.body = { data: { archived: true }, meta: { requestId: ctx.state.requestId } };
203	    },
204	  );
205	
206	  return router;
207	}
