4	/**
5	 * Versioned repository factory.
6	 *
7	 * Creates a repository with consistent CRUD + versioning operations for any
8	 * of the 8 university-data entities. Eliminates 8× code duplication.
9	 *
10	 * @param {object} config
11	 * @param {string} config.stableTable       e.g. 'universities'
12	 * @param {string} config.versionsTable     e.g. 'university_versions'
13	 * @param {string} config.stableIdColumn    e.g. 'university_id'
14	 * @returns {object}  Repository with standard versioning operations
15	 */
16	export function makeVersionedRepository(config) {
17	  const { stableTable, versionsTable, stableIdColumn } = config;
18	
19	  return {
20	    /**
21	     * Create a stable entity record + initial draft version.
22	     */
23	    async create(stableData, versionPayload, actorId, trx) {
24	      const db = trx || knex;
25	
26	      const [stable] = await db(stableTable)
27	        .insert({ ...stableData, created_by: actorId })
28	        .returning('*');
29	
30	      const [version] = await db(versionsTable)
31	        .insert({
32	          [stableIdColumn]: stable.id,
33	          version_number: 1,
34	          lifecycle_status: 'draft',
35	          effective_from: versionPayload.effectiveFrom || new Date().toISOString().split('T')[0],
36	          payload_json: JSON.stringify(versionPayload),
37	          created_by: actorId,
38	        })
39	        .returning('*');
40	
41	      return { stable, version };
42	    },
43	
44	    /**
45	     * Get the current active version of an entity.
46	     */
47	    async findCurrent(stableId, trx) {
48	      const db = trx || knex;
49	      const version = await db(versionsTable)
50	        .where({ [stableIdColumn]: stableId, lifecycle_status: 'active' })
51	        .first();
52	      if (!version) throw new NotFoundError(`${stableTable} not found or has no active version`);
53	      return version;
54	    },
55	
56	    /**
57	     * Find a specific version by its ID, scoped to a stable entity.
58	     * Prevents cross-entity version leakage via UUID guessing.
59	     */
60	    async findVersionById(stableId, versionId, trx) {
61	      const db = trx || knex;
62	      const version = await db(versionsTable)
63	        .where({ id: versionId, [stableIdColumn]: stableId })
64	        .first();
65	      if (!version) throw new NotFoundError('Version not found');
66	      return version;
67	    },
68	
69	    /**
70	     * Get the active or most recent version as of a specific date.
71	     */
72	    async findAtPointInTime(stableId, asOf, trx) {
73	      const db = trx || knex;
74	      return db(versionsTable)
75	        .where({ [stableIdColumn]: stableId })
76	        .where('effective_from', '<=', asOf)
77	        .whereIn('lifecycle_status', ['active', 'superseded'])
78	        .orderBy('version_number', 'desc')
79	        .first();
80	    },
81	
82	    /**
83	     * List all versions for an entity (history).
84	     */
85	    async findHistory(stableId, trx) {
86	      const db = trx || knex;
87	      return db(versionsTable)
88	        .where({ [stableIdColumn]: stableId })
89	        .orderBy('version_number', 'desc');
90	    },
91	
92	    /**
93	     * Update a draft version. Published versions are immutable.
94	     * stableId is required to prevent cross-entity write via UUID guessing.
95	     */
96	    async updateDraft(stableId, versionId, payload, actorId, trx) {
97	      const db = trx || knex;
98	
99	      const existing = await db(versionsTable)
100	        .where({ id: versionId, [stableIdColumn]: stableId })
101	        .first();
102	      if (!existing) throw new NotFoundError('Version not found');
103	      if (existing.lifecycle_status !== 'draft') {
104	        throw new UnprocessableError(
105	          'Only draft versions can be updated. Published versions are immutable.',
106	        );
107	      }
108	
109	      const [updated] = await db(versionsTable)
110	        .where({ id: versionId })
111	        .update({
112	          payload_json: JSON.stringify(payload),
113	          effective_from: payload.effectiveFrom || existing.effective_from,
114	          updated_at: new Date().toISOString(),
115	        })
116	        .returning('*');
117	
118	      return updated;
119	    },
120	
121	    /**
122	     * Publish a draft version.
123	     * Must be called inside withTransaction() from the service layer.
124	     *
125	     * Transitions:
126	     *   - Immediate effective date → new version becomes 'active', prior active becomes 'superseded'
127	     *   - Future effective date → new version becomes 'scheduled'
128	     */
129	    async publishVersion(stableId, versionId, actorId, trx, effectiveFrom) {
130	      const db = trx || knex;
131	
132	      const version = await db(versionsTable)
133	        .where({ id: versionId, [stableIdColumn]: stableId })
134	        .first();
135	      if (!version) throw new NotFoundError('Version not found');
136	      if (version.lifecycle_status !== 'draft') {
137	        throw new UnprocessableError('Only draft versions can be published');
138	      }
139	
140	      // Determine next version number.
141	      // Exclude drafts: draft version_numbers are provisional placeholders and must not
142	      // shift the published sequence. Only committed (non-draft) rows anchor the counter.
143	      const maxRow = await db(versionsTable)
144	        .where({ [stableIdColumn]: version[stableIdColumn] })
145	        .whereNot('lifecycle_status', 'draft')
146	        .max('version_number as max')
147	        .first();
148	      const nextVersionNumber = (maxRow?.max || 0) + 1;
149	
150	      const today = new Date().toISOString().split('T')[0];
151	      // effectiveFrom from publish request takes precedence over the stored draft value
152	      const effectiveDate = effectiveFrom || version.effective_from;
153	      const isImmediate = effectiveDate <= today;
154	      const newStatus = isImmediate ? 'active' : 'scheduled';
155	
156	      if (isImmediate) {
157	        // Retire current active version to 'superseded'
158	        await db(versionsTable)
159	          .where({ [stableIdColumn]: version[stableIdColumn], lifecycle_status: 'active' })
160	          .update({ lifecycle_status: 'superseded', updated_at: new Date().toISOString() });
161	      }
162	
163	      const [published] = await db(versionsTable)
164	        .where({ id: versionId })
165	        .update({
166	          lifecycle_status: newStatus,
167	          version_number: nextVersionNumber,
168	          effective_from: effectiveDate, // persist the resolved date (may override draft value)
169	          published_at: new Date().toISOString(),
170	          published_by: actorId,
171	          updated_at: new Date().toISOString(),
172	        })
173	        .returning('*');
174	
175	      return published;
176	    },
177	
178	    /**
179	     * Archive an entity and its active version.
180	     */
181	    async archive(stableId, actorId, trx) {
182	      const db = trx || knex;
183	      await db(versionsTable)
184	        .where({ [stableIdColumn]: stableId })
185	        .whereIn('lifecycle_status', ['active', 'draft', 'scheduled'])
186	        .update({ lifecycle_status: 'archived', updated_at: new Date().toISOString() });
187	    },
188	
189	    /**
190	     * List all stable entities with their current active version.
191	     */
192	    async listCurrent(filters = {}, pagination = {}, trx) {
193	      const db = trx || knex;
194	      const { page = 1, pageSize = 20 } = pagination;
195	      const offset = (page - 1) * pageSize;
196	
197	      const q = db(stableTable)
198	        .join(versionsTable, `${versionsTable}.${stableIdColumn}`, `${stableTable}.id`)
199	        .where(`${versionsTable}.lifecycle_status`, 'active');
200	
201	      const total = await q.clone().count(`${stableTable}.id as count`).first().then((r) => Number(r.count));
202	      const rows = await q
203	        .select(`${stableTable}.*`, `${versionsTable}.*`, `${stableTable}.id as stable_id`)
204	        .limit(pageSize)
205	        .offset(offset)
206	        .orderBy(`${stableTable}.created_at`, 'desc');
207	
208	      return { rows, total };
209	    },
210	
211	    /**
212	     * Promote all due scheduled versions to active for a given entity.
213	     *
214	     * Called either:
215	     *   a) by the POST /:stableId/versions/:versionId/activate endpoint (manual), or
216	     *   b) by the scheduled-version promotion script (automated).
217	     *
218	     * Transactional guarantee: supersedes the current active version first,
219	     * then promotes the scheduled version — same enforcement as publishVersion.
220	     *
221	     * Only promotes if effective_from <= today. Returns the promoted version
222	     * or null if no promotion was due.
223	     */
224	    /**
225	     * @param {string}  stableId
226	     * @param {string}  actorId
227	     * @param {object}  [trx]       Knex transaction (optional)
228	     * @param {string}  [versionId] When supplied (manual activate endpoint), promote only
229	     *                              that specific version; reject if it is not yet due.
230	     *                              When omitted (cron script), promote the earliest due version.
231	     */
232	    async promoteScheduled(stableId, actorId, trx, versionId) {
233	      const db = trx || knex;
234	      const today = new Date().toISOString().split('T')[0];
235	
236	      let candidate;
237	      if (versionId) {
238	        // Manual activation: target the exact version and validate it is due
239	        candidate = await db(versionsTable)
240	          .where({ id: versionId, [stableIdColumn]: stableId, lifecycle_status: 'scheduled' })
241	          .first();
242	        if (!candidate) return null; // Not found, wrong entity, or not scheduled
243	        if (candidate.effective_from > today) {
244	          const err = new Error(
245	            `Version effective_from ${candidate.effective_from} is not yet due (today is ${today})`,
246	          );
247	          err.code = 'NOT_DUE';
248	          throw err;
249	        }
250	      } else {
251	        // Automated: find the scheduled version with the earliest due effective_from
252	        candidate = await db(versionsTable)
253	          .where({ [stableIdColumn]: stableId, lifecycle_status: 'scheduled' })
254	          .where('effective_from', '<=', today)
255	          .orderBy('effective_from', 'asc')
256	          .first();
257	      }
258	
259	      if (!candidate) return null;
260	
261	      // Supersede the currently active version (if any)
262	      await db(versionsTable)
263	        .where({ [stableIdColumn]: stableId, lifecycle_status: 'active' })
264	        .update({ lifecycle_status: 'superseded', updated_at: new Date().toISOString() });
265	
266	      // Promote the scheduled candidate
267	      const [promoted] = await db(versionsTable)
268	        .where({ id: candidate.id })
269	        .update({
270	          lifecycle_status: 'active',
271	          updated_at: new Date().toISOString(),
272	        })
273	        .returning('*');
274	
275	      return promoted;
276	    },
277	
278	    /**
279	     * Create a new draft version from the current state.
280	     */
281	    async createNewDraft(stableId, payload, actorId, trx) {
282	      const db = trx || knex;
283	
284	      // Derive the next version number from the published sequence only.
285	      // Excluding drafts keeps the numbering single-source: the same counter
286	      // used by publishVersion, so a draft's provisional number matches what
287	      // publish will assign and no reassignment occurs at publish time.
288	      const maxRow = await db(versionsTable)
289	        .where({ [stableIdColumn]: stableId })
290	        .whereNot('lifecycle_status', 'draft')
291	        .max('version_number as max')
292	        .first();
293	      const nextVersionNumber = (maxRow?.max || 0) + 1;
294	
295	      const [version] = await db(versionsTable)
296	        .insert({
297	          [stableIdColumn]: stableId,
298	          version_number: nextVersionNumber,
299	          lifecycle_status: 'draft',
300	          effective_from: payload.effectiveFrom || new Date().toISOString().split('T')[0],
301	          payload_json: JSON.stringify(payload),
302	          created_by: actorId,
303	        })
304	        .returning('*');
305	
306	      return version;
307	    },
308	  };
309	}
