23	export const assignmentService = {
24	  /**
25	   * Create a single assignment (manual or direct).
26	   */
27	  async create({ applicationId, reviewerId, cycleId, mode, blindMode, assignedBy, dueAt }, requestId) {
28	    // Validate application and reviewer exist
29	    const [app, reviewer] = await Promise.all([
30	      knex('applications').where({ id: applicationId }).first(),
31	      knex('reviewer_profiles').where({ id: reviewerId }).first(),
32	    ]);
33	    if (!app) throw new NotFoundError('Application not found');
34	    if (!reviewer) throw new NotFoundError('Reviewer not found');
35	    if (!reviewer.active || !reviewer.available) {
36	      throw new UnprocessableError('Reviewer is not available for assignment');
37	    }
38	    if (reviewer.active_assignments >= reviewer.max_load) {
39	      throw new UnprocessableError('Reviewer has reached maximum assignment load');
40	    }
41	
42	    // Derive cycle_id from the application record — never trust the client value
43	    const resolvedCycleId = app.cycle_id;
44	    if (!resolvedCycleId) throw new UnprocessableError('Application is not associated with a review cycle');
45	    if (cycleId && cycleId !== resolvedCycleId) {
46	      throw new UnprocessableError(
47	        'Supplied cycleId does not match the application\'s review cycle',
48	      );
49	    }
50	
51	    const { hasConflict, reasons } = await coiService.checkConflict(reviewerId, applicationId);
52	    await coiService.recordCheck({
53	      reviewerId, applicationId, hasConflict, reasons, checkedBy: assignedBy,
54	    });
55	
56	    if (hasConflict) {
57	      throw new UnprocessableError(
58	        'Assignment blocked due to conflict of interest',
59	        reasons.map((r) => ({ field: 'reviewer', issue: r.detail })),
60	      );
61	    }
62	
63	    return withTransaction(async (trx) => {
64	      const [assignment] = await trx('review_assignments')
65	        .insert({
66	          application_id: applicationId,
67	          reviewer_id: reviewerId,
68	          cycle_id: resolvedCycleId,
69	          assignment_mode: mode || 'manual',
70	          blind_mode: blindMode || 'blind',
71	          assigned_by: assignedBy,
72	          due_at: dueAt || null,
73	        })
74	        .returning('*');
75	
76	      // Update reviewer load counter
77	      await trx('reviewer_profiles')
78	        .where({ id: reviewerId })
79	        .increment('active_assignments', 1);
80	
81	      await auditService.record({
82	        actorAccountId: assignedBy,
83	        actionType: 'review_assignment.created',
84	        entityType: 'review_assignment',
85	        entityId: assignment.id,
86	        requestId,
87	        afterSummary: { applicationId, reviewerId, mode: assignment.assignment_mode },
88	      }, trx);
89	
90	      return assignment;
91	    });
92	  },
93	
94	  /**
95	   * Batch assignment — randomly or by rules.
96	   * Assigns the minimum required number of reviewers to each application,
97	   * filtered by COI and load balance.
98	   *
99	   * @param {object} params
100	   * @param {string[]} params.applicationIds
101	   * @param {string} params.cycleId
102	   * @param {string} params.mode  'random' | 'rule_based'
103	   * @param {string} params.blindMode
104	   * @param {number} params.reviewersPerApplication
105	   * @param {string} params.assignedBy  Actor account ID
106	   */
107	  async batchAssign({ applicationIds, cycleId, mode, blindMode, reviewersPerApplication, assignedBy }, requestId) {
108	    const minReviewers = reviewersPerApplication || reviewPolicies.assignment.minReviewersPerApplication;
109	
110	    // Load all applications to derive cycle_id server-side
111	    const applications = await knex('applications')
112	      .whereIn('id', applicationIds)
113	      .select('id', 'cycle_id');
114	
115	    const foundIds = new Set(applications.map((a) => a.id));
116	    const missing = applicationIds.filter((id) => !foundIds.has(id));
117	    if (missing.length) throw new NotFoundError(`Applications not found: ${missing.join(', ')}`);
118	
119	    // Build per-application cycle_id map and validate all belong to the same cycle
120	    const appCycleMap = new Map(applications.map((a) => [a.id, a.cycle_id]));
121	    const distinctCycles = new Set(applications.map((a) => a.cycle_id).filter(Boolean));
122	    if (distinctCycles.size === 0) throw new UnprocessableError('Applications are not associated with any review cycle');
123	    if (distinctCycles.size > 1) {
124	      throw new UnprocessableError('All applications in a batch must belong to the same review cycle');
125	    }
126	    const resolvedCycleId = [...distinctCycles][0];
127	
128	    // If client supplied cycleId, validate it matches
129	    if (cycleId && cycleId !== resolvedCycleId) {
130	      throw new UnprocessableError(
131	        'Supplied cycleId does not match the applications\' review cycle',
132	      );
133	    }
134	
135	    // Load eligible reviewers
136	    const eligibleReviewers = await knex('reviewer_profiles')
137	      .where({ available: true, active: true })
138	      .whereRaw('active_assignments < max_load')
139	      .select('id', 'expertise_tags', 'max_load', 'active_assignments');
140	
141	    if (eligibleReviewers.length === 0) {
142	      throw new UnprocessableError('No eligible reviewers available for assignment');
143	    }
144	
145	    // ── Rule-based: rank reviewers by expertise match per application ─────────
146	    // ── Random: shuffle pool once and apply uniformly ─────────────────────────
147	    let reviewerOrderByApp = null; // Map<appId, reviewer[]> — only set for rule_based
148	
149	    if (mode === 'rule_based') {
150	      // Load the program choices (major→field) for each application so we can
151	      // match against reviewer expertise_tags.
152	      const programRows = await knex('application_program_choices as apc')
153	        .join('major_versions as mv', function () {
154	          this.on('mv.major_id', '=', 'apc.major_id').andOn(
155	            'mv.lifecycle_status', '=', knex.raw("'active'"),
156	          );
157	        })
158	        .whereIn('apc.application_id', applicationIds)
159	        .select(
160	          'apc.application_id',
161	          knex.raw("LOWER(mv.payload_json->>'name') AS program_name"),
162	          knex.raw("LOWER(mv.payload_json->>'field') AS program_field"),
163	        );
164	
165	      // Build per-application keyword set
166	      const appKeywords = new Map(applicationIds.map((id) => [id, new Set()]));
167	      for (const row of programRows) {
168	        const kw = appKeywords.get(row.application_id);
169	        if (kw) {
170	          if (row.program_name) kw.add(row.program_name);
171	          if (row.program_field) kw.add(row.program_field);
172	        }
173	      }
174	
175	      // Score reviewers per application
176	      reviewerOrderByApp = new Map();
177	      for (const appId of applicationIds) {
178	        const keywords = appKeywords.get(appId) || new Set();
179	        const scored = eligibleReviewers.map((r) => {
180	          const tags = (r.expertise_tags || []).map((t) => String(t).toLowerCase());
181	          const matchCount = tags.filter((t) => keywords.has(t)).length;
182	          // Secondary sort: prefer reviewers with more available capacity
183	          const capacity = r.max_load - r.active_assignments;
184	          return { reviewer: r, matchCount, capacity };
185	        });
186	        // Sort: most expertise matches first, then most available capacity
187	        scored.sort((a, b) => b.matchCount - a.matchCount || b.capacity - a.capacity);
188	        reviewerOrderByApp.set(appId, scored.map((s) => s.reviewer));
189	      }
190	    }
191	
192	    const shuffledReviewers = secureShuffle(eligibleReviewers);
193	
194	    // Build candidate pairs for batch COI check
195	    const candidatePairs = [];
196	    for (const appId of applicationIds) {
197	      const reviewerList = reviewerOrderByApp ? reviewerOrderByApp.get(appId) : shuffledReviewers;
198	      for (const reviewer of (reviewerList || shuffledReviewers)) {
199	        candidatePairs.push({ reviewerId: reviewer.id, applicationId: appId });
200	      }
201	    }
202	
203	    // Batch COI check — returns set of conflicted pairs
204	    const conflictedPairs = await coiService.batchCheck(candidatePairs);
205	
206	    // Filter valid assignments per application.
207	    // reservedCounts tracks how many assignments have been planned for each reviewer
208	    // within this batch so we don't exceed max_load across multiple applications.
209	    const assignments = [];
210	    const errors = [];
211	    const reservedCounts = new Map();
212	
213	    for (const appId of applicationIds) {
214	      const orderedReviewers = reviewerOrderByApp
215	        ? (reviewerOrderByApp.get(appId) || shuffledReviewers)
216	        : shuffledReviewers;
217	
218	      const validReviewers = orderedReviewers.filter(
219	        (r) =>
220	          !conflictedPairs.has(`${r.id}:${appId}`) &&
221	          r.active_assignments + (reservedCounts.get(r.id) || 0) < r.max_load,
222	      );
223	
224	      if (validReviewers.length < minReviewers) {
225	        errors.push({ applicationId: appId, issue: 'Insufficient eligible reviewers after COI filtering' });
226	        continue;
227	      }
228	
229	      for (const reviewer of validReviewers.slice(0, minReviewers)) {
230	        assignments.push({
231	          application_id: appId,
232	          reviewer_id: reviewer.id,
233	          cycle_id: appCycleMap.get(appId) || resolvedCycleId,
234	          assignment_mode: mode || 'random',
235	          blind_mode: blindMode || 'blind',
236	          assigned_by: assignedBy,
237	        });
238	        // Reserve capacity so subsequent applications in this batch see the updated load
239	        reservedCounts.set(reviewer.id, (reservedCounts.get(reviewer.id) || 0) + 1);
240	      }
241	    }
242	
243	    if (assignments.length === 0) {
244	      throw new UnprocessableError('No valid assignments could be created', errors);
245	    }
246	
247	    return withTransaction(async (trx) => {
248	      const created = await trx('review_assignments')
249	        .insert(assignments)
250	        .onConflict(['application_id', 'reviewer_id', 'cycle_id'])
251	        .ignore()
252	        .returning('*');
253	
254	      // Update reviewer load counters
255	      const reviewerCounts = {};
256	      for (const a of created) {
257	        reviewerCounts[a.reviewer_id] = (reviewerCounts[a.reviewer_id] || 0) + 1;
258	      }
259	      for (const [reviewerId, count] of Object.entries(reviewerCounts)) {
260	        await trx('reviewer_profiles')
261	          .where({ id: reviewerId })
262	          .increment('active_assignments', count);
263	      }
264	
265	      await auditService.record({
266	        actorAccountId: assignedBy,
267	        actionType: 'review_assignment.batch_created',
268	        entityType: 'review_assignment',
269	        entityId: resolvedCycleId,
270	        requestId,
271	        afterSummary: { count: created.length, mode, errors: errors.length },
272	      }, trx);
273	
274	      return { created, errors };
275	    });
276	  },
277	
278	  async getById(assignmentId, viewer) {
279	    const assignment = await knex('review_assignments').where({ id: assignmentId }).first();
280	    if (!assignment) throw new NotFoundError('Assignment not found');
281	
282	    // Object-level check: reviewers can only see their own assignments
283	    const isAdmin = viewer.roles?.includes('SYSTEM_ADMIN') || viewer.roles?.includes('PROGRAM_ADMIN');
284	    if (!isAdmin) {
285	      const reviewerProfile = await knex('reviewer_profiles')
286	        .where({ account_id: viewer.id })
287	        .first('id');
288	      if (!reviewerProfile || assignment.reviewer_id !== reviewerProfile.id) {
289	        throw new NotFoundError('Assignment not found'); // Use 404 to avoid information leak
290	      }
291	    }
292	
293	    return assignment;
294	  },
295	
296	  async list(filters, viewer) {
297	    const isAdmin = viewer.roles?.includes('SYSTEM_ADMIN') || viewer.roles?.includes('PROGRAM_ADMIN');
298	    let q = knex('review_assignments').orderBy('assigned_at', 'desc');
299	
300	    if (!isAdmin) {
301	      const reviewerProfile = await knex('reviewer_profiles')
302	        .where({ account_id: viewer.id })
303	        .first('id');
304	      if (!reviewerProfile) return { rows: [], total: 0 };
305	      q = q.where('reviewer_id', reviewerProfile.id);
306	    }
307	
308	    if (filters.cycleId) q = q.where('cycle_id', filters.cycleId);
309	    if (filters.status) q = q.where('status', filters.status);
310	
311	    const total = await q.clone().count('id as count').first().then((r) => Number(r.count));
312	    const page = Number(filters.page) || 1;
313	    const pageSize = Math.min(Number(filters.pageSize) || 20, 100);
314	    const rows = await q.limit(pageSize).offset((page - 1) * pageSize);
315	
316	    return { rows, total };
317	  },
318	};
