20	const batchAssignSchema = z.object({
21	  applicationIds: z.array(z.string().uuid()).min(1).max(500),
22	  // cycleId is optional — the server derives it from the application records.
23	  // If supplied, all applications must belong to that cycle; mismatches are rejected as 422.
24	  cycleId: z.string().uuid().optional(),
25	  mode: z.enum(['random', 'rule_based']).default('random'),
26	  blindMode: z.enum(['blind', 'semi_blind', 'full']).default('blind'),
27	  reviewersPerApplication: z.number().int().min(1).max(10).optional(),
