47	  '/batch',
48	  requirePermission('review-assignments', 'manage'),
49	  validate({ body: batchAssignSchema }),
50	  async (ctx) => {
51	    const result = await assignmentService.batchAssign(
52	      { ...ctx.request.body, assignedBy: ctx.state.user.id },
53	      ctx.state.requestId,
54	    );
55	    ctx.status = 201;
56	    ctx.body = {
57	      data: result.created,
58	      meta: {
59	        requestId: ctx.state.requestId,
60	        total: result.created.length,
61	        errors: result.errors,
62	      },
63	    };
64	  },
