1	/**
2	 * Base application error.
3	 * All domain errors extend this class.
4	 * The error handler middleware serialises AppError instances into the standard
5	 * response envelope: { error: { code, message, details }, meta: { requestId } }
6	 */
7	export class AppError extends Error {
8	  /**
9	   * @param {string} message  Human-readable message (safe to expose to clients)
10	   * @param {number} statusCode  HTTP status code
11	   * @param {string} code  Machine-readable error code (e.g. 'VALIDATION_ERROR')
12	   * @param {Array}  details  Optional field-level error details
13	   */
14	  constructor(message, statusCode = 500, code = 'INTERNAL_ERROR', details = []) {
15	    super(message);
16	    this.name = this.constructor.name;
17	    this.statusCode = statusCode;
18	    this.code = code;
19	    this.details = details;
20	    Error.captureStackTrace(this, this.constructor);
21	  }
22	}
23	
24	/** 400 — Request body / query / params failed Zod validation */
25	export class ValidationError extends AppError {
26	  constructor(message = 'Validation failed', details = []) {
27	    super(message, 400, 'VALIDATION_ERROR', details);
28	  }
29	}
30	
31	/** 401 — Missing or invalid session token */
32	export class AuthenticationError extends AppError {
33	  constructor(message = 'Authentication required') {
34	    super(message, 401, 'AUTHENTICATION_ERROR');
35	  }
36	}
37	
38	/** 403 — Authenticated but insufficient permissions */
39	export class AuthorizationError extends AppError {
40	  constructor(message = 'Insufficient permissions') {
41	    super(message, 403, 'AUTHORIZATION_ERROR');
42	  }
43	}
44	
45	/** 404 — Entity not found (use generic message to avoid leaking what was not found) */
46	export class NotFoundError extends AppError {
47	  constructor(message = 'Resource not found') {
48	    super(message, 404, 'NOT_FOUND');
49	  }
50	}
51	
52	/** 409 — Duplicate idempotency key with different body, or publish version conflict */
53	export class ConflictError extends AppError {
54	  constructor(message = 'Conflict', details = []) {
55	    super(message, 409, 'CONFLICT', details);
56	  }
57	}
58	
59	/** 413 — Attachment too large */
60	export class PayloadTooLargeError extends AppError {
61	  constructor(message = 'Payload too large') {
62	    super(message, 413, 'PAYLOAD_TOO_LARGE');
63	  }
64	}
65	
66	/** 415 — Unsupported attachment MIME type */
67	export class UnsupportedMediaTypeError extends AppError {
68	  constructor(message = 'Unsupported media type') {
69	    super(message, 415, 'UNSUPPORTED_MEDIA_TYPE');
70	  }
71	}
72	
73	/** 422 — Semantically invalid business rule input (weights don't sum to 100, COI detected, etc.) */
74	export class UnprocessableError extends AppError {
75	  constructor(message = 'Unprocessable request', details = []) {
76	    super(message, 422, 'UNPROCESSABLE', details);
77	  }
78	}
