1	import { z } from 'zod';
2	
3	/**
4	 * Shared Zod schemas for versioned entity operations.
5	 */
6	
7	/**
8	 * Validate a YYYY-MM-DD string as a real calendar date.
9	 * new Date('2026-02-30') normalises silently in JS, so we verify by round-tripping
10	 * through UTC component values — if the normalised result differs from the input,
11	 * the date is out of range for that month.
12	 */
13	function isRealCalendarDate(iso) {
14	  const [y, m, d] = iso.split('-').map(Number);
15	  const dt = new Date(Date.UTC(y, m - 1, d));
16	  return (
17	    dt.getUTCFullYear() === y &&
18	    dt.getUTCMonth() + 1 === m &&
19	    dt.getUTCDate() === d
20	  );
21	}
22	
23	// MM/DD/YYYY → YYYY-MM-DD conversion and validation
24	const effectiveDateSchema = z
25	  .string()
26	  .regex(/^\d{2}\/\d{2}\/\d{4}$/, 'Date must be MM/DD/YYYY format')
27	  .transform((s) => {
28	    const [mm, dd, yyyy] = s.split('/');
29	    return `${yyyy}-${mm}-${dd}`;
30	  })
31	  .refine(isRealCalendarDate, { message: 'Invalid date' })
32	  .or(
33	    // Also accept ISO format directly
34	    z.string()
35	      .regex(/^\d{4}-\d{2}-\d{2}$/)
36	      .refine(isRealCalendarDate, { message: 'Invalid date' })
37	  );
38	
39	export const publishVersionSchema = z.object({
40	  effectiveFrom: effectiveDateSchema.optional(),
41	});
42	
43	export const createDraftSchema = z.object({
44	  effectiveFrom: effectiveDateSchema.optional(),
45	  changeSummary: z.string().max(500).optional(),
46	});
47	
48	export const paginationSchema = z.object({
49	  page: z.coerce.number().int().min(1).default(1),
50	  pageSize: z.coerce.number().int().min(1).max(100).default(20),
51	});
52	
53	export const versionParamsSchema = z.object({
54	  stableId: z.string().uuid(),
55	  versionId: z.string().uuid().optional(),
56	});
57	
58	/**
59	 * Creates a standard "create entity" schema with a required name + optional description.
60	 */
61	export function makeCreateEntitySchema(extraFields = {}) {
62	  return z.object({
63	    name: z.string().min(1).max(500),
64	    description: z.string().max(2000).optional(),
65	    effectiveFrom: effectiveDateSchema.optional(),
66	    changeSummary: z.string().max(500).optional(),
67	    ...extraFields,
68	  });
69	}
