4	
5	/**
6	 * Creates a standard versioned entity service for a given entity type.
7	 * All 8 university-data entities use this factory.
8	 *
9	 * @param {object} config
10	 * @param {string} config.stableTable
11	 * @param {string} config.versionsTable
12	 * @param {string} config.stableIdColumn
13	 * @param {string} config.entityType   For audit events e.g. 'university'
14	 */
15	export function makeVersionedService(config) {
16	  const repo = makeVersionedRepository(config);
17	  const { entityType } = config;
18	
19	  return {
20	    async create(stableData, versionPayload, actorId, requestId) {
21	      return withTransaction(async (trx) => {
22	        const result = await repo.create(stableData, versionPayload, actorId, trx);
23	        await auditService.record({
24	          actorAccountId: actorId,
25	          actionType: `${entityType}.created`,
26	          entityType,
27	          entityId: result.stable.id,
28	          requestId,
29	          afterSummary: { name: versionPayload.name, status: 'draft' },
30	        }, trx);
31	        return result;
32	      });
33	    },
34	
35	    async createNewDraft(stableId, payload, actorId, requestId) {
36	      return withTransaction(async (trx) => {
37	        const version = await repo.createNewDraft(stableId, payload, actorId, trx);
38	        await auditService.record({
39	          actorAccountId: actorId,
40	          actionType: `${entityType}.draft_created`,
41	          entityType,
42	          entityId: stableId,
43	          requestId,
44	          afterSummary: { versionNumber: version.version_number },
45	        }, trx);
46	        return version;
47	      });
48	    },
49	
50	    async updateDraft(stableId, versionId, payload, actorId, requestId) {
51	      return withTransaction(async (trx) => {
52	        const version = await repo.updateDraft(stableId, versionId, payload, actorId, trx);
53	        await auditService.record({
54	          actorAccountId: actorId,
55	          actionType: `${entityType}.draft_updated`,
56	          entityType,
57	          entityId: stableId,
58	          requestId,
59	          afterSummary: { versionId },
60	        }, trx);
61	        return version;
62	      });
63	    },
64	
65	    async publish(stableId, versionId, actorId, requestId, effectiveFrom) {
66	      return withTransaction(async (trx) => {
67	        const version = await repo.publishVersion(stableId, versionId, actorId, trx, effectiveFrom);
68	        await auditService.record({
69	          actorAccountId: actorId,
70	          actionType: `${entityType}.version_published`,
71	          entityType,
72	          entityId: stableId,
73	          requestId,
74	          afterSummary: {
75	            versionId,
76	            versionNumber: version.version_number,
77	            lifecycleStatus: version.lifecycle_status,
78	            effectiveFrom: version.effective_from,
79	          },
80	        }, trx);
81	        return version;
82	      });
83	    },
84	
85	    async archive(stableId, actorId, requestId) {
86	      return withTransaction(async (trx) => {
87	        await repo.archive(stableId, actorId, trx);
88	        await auditService.record({
89	          actorAccountId: actorId,
90	          actionType: `${entityType}.archived`,
91	          entityType,
92	          entityId: stableId,
93	          requestId,
94	        }, trx);
95	      });
96	    },
97	
98	    async promoteScheduled(stableId, actorId, requestId, versionId) {
99	      return withTransaction(async (trx) => {
100	        const version = await repo.promoteScheduled(stableId, actorId, trx, versionId);
101	        if (version) {
102	          await auditService.record({
103	            actorAccountId: actorId,
104	            actionType: `${entityType}.scheduled_promoted`,
105	            entityType,
106	            entityId: stableId,
107	            requestId,
108	            afterSummary: {
109	              versionId: version.id,
110	              versionNumber: version.version_number,
111	              effectiveFrom: version.effective_from,
112	            },
113	          }, trx);
114	        }
115	        return version;
116	      });
117	    },
118	
119	    findCurrent: (stableId, trx) => repo.findCurrent(stableId, trx),
120	    findVersionById: (stableId, versionId, trx) => repo.findVersionById(stableId, versionId, trx),
121	    findHistory: (stableId, trx) => repo.findHistory(stableId, trx),
122	    findAtPointInTime: (stableId, asOf, trx) => repo.findAtPointInTime(stableId, asOf, trx),
123	    listCurrent: (filters, pagination, trx) => repo.listCurrent(filters, pagination, trx),
124	  };
125	}
